var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"내 연구실에 온 걸 환영하네, 엠버 박사.","JPN":"我が研究室にようこそ、アンバー博士。","ENG":"Welcome to my lab, Dr. Ember.","TWN":"琥珀博士，歡迎你來到我的研究室。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"아들내미 말로는 이번에도 다른 과학자들과 한바탕 했다던데……. 신수가 훤하구만.","JPN":"息子の話では、今回も他の科学者たちと派手にやりあったと聞いたが……\\nずいぶんと機嫌が良さそうだな。","ENG":"I heard from my son that you did a number on the other scientists? I like your style.","TWN":"我聽小犬說，這次博士和其他科學家又有些意見是嗎……真是有活力呢～"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"오랜만이네요. 회장님.","JPN":"お久しぶりです、会長。","ENG":"Good to see you again, sir.","TWN":"會長，好久不見。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이번에 인수한 기업 사장이 회사 건물에서 투신했다면서요?","JPN":"今回買収した企業の社長が、会社から飛び降りたらしいですね。","ENG":"I heard that the former president of the company that you took over jumped from the company building.","TWN":"我聽說會長這次接手的公司，那個老闆從公司一躍而下？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"애도라도 표하셨나 모르겠네요. 뉴스 본 지도 오래돼서.","JPN":"哀悼はしましたか？　ニュースはしばらく見ていないので。","ENG":"Did you send your condolences? I haven't watched the news in a long time.","TWN":"不知道會長有為他哀悼嗎？雖然我是很久以前在新聞上看到的。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그놈이 회사를 좀 맡아 주십쇼, 하고 빌길래 사들인 건데 내가 왜 애도를 표하나?","JPN":"あいつから自分の会社をお願いしたいとすがりつくから買ってやったのに、\\nなぜ私が心を痛めねばならんのだ？","ENG":"He’s the one who begged me to take it from him. Why should I pay him my respect?","TWN":"是那傢伙來求我接收他的公司的，我有什麼好哀悼的？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"시장은 먹고 먹히는 곳이야. 누가 인수하려고 마음 먹었나 싶으면 대비를 해야지.","JPN":"喰って、喰われる業界だ。誰かに買収されるとわかったなら、それに備えなければな。","ENG":"It’s a dog-eat-dog world out there. When he heard that someone was attempting to take over, he should have prepared.","TWN":"做生意本來就是彼此勾心鬥角，要是發現有人想收購公司，就必須事先想好對策，超前佈署。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"언론에서 비난하는 건 회장님이 인수 전에 하신 밑준비 같던데요.","JPN":"マスコミが非難しているのは、会長が買収前にした下準備のことだそうですが。","ENG":"Isn't it the preparation for the merger that the media is criticizing you for?","TWN":"輿論上說會長是有計畫收購人家公司的呢？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……그놈 가족에게는 내 넉넉히 챙겨 줬어. 그러니 더 말 말게.","JPN":"……奴の家族には十分なほど渡してやった。だからこれ以上は言わないでくれ。","ENG":"I gave his family a hefty settlement check. Now, enough talk about this.","TWN":"……我可沒有虧待他的家人，這沒什麼好再說的。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"고약한 성질머리는 여전하시군요.","JPN":"人間味がないのは相変わらずですね。","ENG":"I see you’re hot-headed as usual.","TWN":"會長的脾氣還是那麼硬呢～"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"나와 말싸움이나 하자고 온 건가?","JPN":"私と口論をするために来たのか？","ENG":"Have you come here to argue with me?","TWN":"你是來和我吵架的嗎？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아뇨. 위기관리 부서에서 강탈한 출처불명의 유전체 지도를 보러 왔습니다.","JPN":"いいえ。危機管理部から強奪した、出所不明のゲノム地図を見に来ました。","ENG":"No, sir. I’ve come to see the unidentified genome map that you stole from the Crisis Management Department.","TWN":"不是的，我是來欣賞被危機管理部門搶走的，來路不明的基因圖譜。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"요정을 만드는 방법이라느니 어쩌니 하던데……. 직접 들여다본 다음 판단하고 싶어서요.","JPN":"『妖精』の作り方がどうのと聞きましたが……直接見て判断したいです。","ENG":"I heard rumors of it containing a method to create fairies, but I wanted to see for myself before passing judgment.","TWN":"似乎跟製造精靈，還什麼的有關……我想親自來確認後再判斷。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"눈치도 빠르군. 언론에는 정신 나간 재야학자가 소란 피운 걸로 나갔을 텐데…….","JPN":"目ざといな。マスコミにはイカれた民間学者が騒ぎ立てたと流したはずだが……","ENG":"Well aren’t you quick-witted. I heard the media reported it as a hysterical scientist's outburst...","TWN":"觀察力不錯嘛，媒體上的報導應該只有提到，某個瘋狂科學家引起騷動吧……"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그래도 마침 잘 왔네.","JPN":"それにしてもちょうどいいところに来た。","ENG":"But I’m glad you came.","TWN":"不過你來得正是時候！"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그분에게 도저히 물을 방도가 없어서 자네를 부르려 하던 참이니까.","JPN":"あの方にお伺いするすべがなくて、君を呼ぼうとしたところだったんだ。","ENG":"I couldn’t find a way to reach The Eminent, so I was about to call you.","TWN":"因為我實在是沒有方法可以問到他，正想找你來問問！"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그분이 누군지는 모르겠지만…… 직원들 보는 앞에서 회장님 얼굴에 파스타를 던진 저를요?","JPN":"あの方が誰かはわかりませんが……\\n社員たちの前で会長の顔にパスタを投げつけた私をですか？","ENG":"I don’t know who you’re talking about, but... you wanted to see me? The girl who threw pasta at her boss’ face in front of everyone?","TWN":"雖然不清楚那個他是指誰……但會長怎麼會想找我？我可是在員工面前，把義大利麵砸在會長臉上呢？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"능력 있는 인재라면 얼굴에 파스타를 던지든 머리털에 불을 붙이든 무슨 상관인가.","JPN":"優れた人材なら顔にパスタを投げつけようが、髪の毛に火をつけようが関係ない。","ENG":"If you have the skills to back it up, it doesn’t matter if you throw pasta or set your boss’ hair on fire.","TWN":"只要是有能力的人才，要在我臉上扔義大利麵，或是在我頭上點火，我都無所謂。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};